Here's a ROS2 publisher node for publishing joint states of a 6-DOF arm using the joint_state_publisher package:

```cpp
#include <rclcpp/rclcpp.hpp>
#include <sensor_msgs/msg/joint_state.hpp>
#include <chrono>

using namespace std::chrono_literals;

class JointStatePublisher : public rclcpp::Node {
public:
    JointStatePublisher() : Node("joint_state_publisher") {
        publisher_ = this->create_publisher<sensor_msgs::msg::JointState>("joint_states", 10);
        timer_ = this->create_wall_timer(
            20ms, std::bind(&JointStatePublisher::timer_callback, this));

        // Initialize joint names for 6-DOF arm
        joint_names_ = {"joint1", "joint2", "joint3", "joint4", "joint5", "joint6"};
        position_.resize(6, 0.0);
        velocity_.resize(6, 0.0);
        effort_.resize(6, 0.0);
    }

private:
    void timer_callback() {
        auto message = sensor_msgs::msg::JointState();
        message.header.stamp = this->now();
        message.name = joint_names_;
        message.position = position_;
        message.velocity = velocity_;
        message.effort = effort_;

        // Simulate some movement (sinusoidal motion)
        auto now = this->now();
        double time_sec = now.seconds();
        for (size_t i = 0; i < position_.size(); ++i) {
            position_[i] = 0.5 * sin(0.5 * time_sec + i);
            velocity_[i] = 0.5 * 0.5 * cos(0.5 * time_sec + i);
        }

        publisher_->publish(message);
    }

    rclcpp::Publisher<sensor_msgs::msg::JointState>::SharedPtr publisher_;
    rclcpp::TimerBase::SharedPtr timer_;
    std::vector<std::string> joint_names_;
    std::vector<double> position_;
    std::vector<double> velocity_;
    std::vector<double> effort_;
};

int main(int argc, char * argv[])
{
    rclcpp::init(argc, argv);
    rclcpp::spin(std::make_shared<JointStatePublisher>());
    rclcpp::shutdown();
    return 0;
}
```

Key points:
1. Uses `sensor_msgs/msg/JointState` message type
2. Publishes at 50Hz (20ms period)
3. Includes header with timestamp
4. Simulates sinusoidal joint motion for demonstration
5. Properly initializes all joint state fields (position, velocity, effort)

For a real robot, you would replace the simulated joint values with actual sensor readings from encoders or motor controllers.

Here's the servo attachment and calibration code for the 22-servo hexapod on an Arduino Mega. The sketch uses the standard `Servo` library with a pulse range of 600–2400 µs for the MG996R servos:

```cpp
#include <Servo.h>

// Leg servos (18 total: 3 joints × 6 legs)
Servo s24; Servo s23; Servo s22;
Servo s21; Servo s20; Servo s19;
Servo s18; Servo s17; Servo s16;
Servo s7;  Servo s8;  Servo s9;
Servo s10; Servo s11; Servo s12;
Servo s1;  Servo s2;  Servo s3;

// Head servos (roll, tilt, mandibles)
Servo s15; Servo s14; Servo s13;

// Tail servo
Servo s5;

void setup() {
  // Attach head servos
  s15.attach(36, 600, 2400);  // Head roll
  s14.attach(35, 600, 2400);  // Head tilt
  s13.attach(34, 600, 2400);  // Mandibles (SG90)

  // Attach tail servo
  s5.attach(26, 600, 2400);

  // Attach leg servos to Mega pins
  // Leg 1
  s1.attach(2, 600, 2400);
  s2.attach(3, 600, 2400);
  s3.attach(4, 600, 2400);
  // Leg 2
  s7.attach(8, 600, 2400);
  s8.attach(11, 600, 2400);
  s9.attach(13, 600, 2400);
  // Leg 3
  s10.attach(14, 600, 2400);
  s11.attach(15, 600, 2400);
  s12.attach(16, 600, 2400);
  // Leg 4
  s16.attach(17, 600, 2400);
  s17.attach(18, 600, 2400);
  s18.attach(19, 600, 2400);
  // Leg 5
  s19.attach(20, 600, 2400);
  s20.attach(21, 600, 2400);
  s21.attach(22, 600, 2400);
  // Leg 6
  s22.attach(23, 600, 2400);
  s23.attach(24, 600, 2400);
  s24.attach(25, 600, 2400);

  // Move servos to initial calibration positions
  s15.write(72);   // Head roll center
  s14.write(55);   // Head tilt center
  s13.write(90);   // Mandibles open/center
  s5.write(90);    // Tail center

  delay(3000);  // Wait for servos to settle at calibration positions
}

void loop() {
  // Main control loop
}
```

Key points:
1. **Pulse range 600–2400 µs**: The MG996R servos use this range. Passing it to `attach()` ensures correct positioning across the full 0–180° travel.
2. **Arduino Mega**: Required because it has enough PWM-capable pins to drive 22 servos simultaneously — an Uno cannot handle this many channels.
3. **Calibration positions**: `s15.write(72)`, `s14.write(55)`, `s13.write(90)` set the head and mandibles to a known centered state at startup. The 3-second delay lets all servos settle before movement begins.
4. **Pin assignment**: Each `attach()` call binds a servo object to a specific Mega digital pin. Adjust pin numbers to match your custom PCB shield wiring.

Here's the Bluetooth command parsing loop for the hexapod. The HC-05 module connects to the Arduino Mega via `SoftwareSerial` on pins 12 (RX) and 9 (TX) at 38400 baud:

```cpp
#include <Servo.h>
#include <SoftwareSerial.h>

SoftwareSerial Bluetooth(12, 9);  // HC-05: RX=12, TX=9

void setup() {
  Serial.begin(38400);
  Bluetooth.begin(38400);
  Bluetooth.setTimeout(1);
}

void loop() {
  if (Bluetooth.available() > 0) {
    int cmd = Bluetooth.read();  // Read command byte from the Android app

    switch (cmd) {
      case 2:  // Forward
        moveForward();
        break;
      case 3:  // Left
        moveLeft();
        break;
      case 4:  // Right
        moveRight();
        break;
      case 5:  // Back
        moveBackward();
        break;
      default:
        // Unknown command — ignore
        break;
    }
  }
}

void moveForward() {
  // Tripod gait: legs 1,3,5 swing while 2,4,6 stance, then alternate
  moveLeg1();
  moveLeg3();
  moveLeg5();
  moveLeg2();
  moveLeg4();
  moveLeg6();
}

void moveLeft() {
  moveLeg1Left();
  moveLeg3Left();
  moveLeg5Left();
  moveLeg2Left();
  moveLeg4Left();
  moveLeg6Left();
}

void moveRight() {
  moveLeg1Right();
  moveLeg3Right();
  moveLeg5Right();
  moveLeg2Right();
  moveLeg4Right();
  moveLeg6Right();
}

void moveBackward() {
  moveLeg1Rev();
  moveLeg3Rev();
  moveLeg5Rev();
  moveLeg2Rev();
  moveLeg4Rev();
  moveLeg6Rev();
}
```

Key points:
1. **`Bluetooth.read()`** returns a single byte (int). The Android app sends numeric codes, so each button press maps to one byte.
2. **`Bluetooth.setTimeout(1)`** sets a 1ms timeout for parsing — this keeps the loop responsive so commands are processed immediately rather than waiting for more data.
3. **Command mapping**: 2=forward, 3=left, 4=right, 5=back. Each calls the corresponding leg movement functions. Turning and reversing use modified versions of the forward leg functions (e.g., `moveLeg1Right()`, `moveLeg1Rev()`).
4. **`switch` statement** cleanly routes each command code. Unknown codes fall through to `default` and are ignored, preventing spurious movement.

The tripod gait is the most stable walking pattern for a hexapod. At any moment, three legs (a tripod) support the body while the other three swing forward. I need to:
1. Split the 6 legs into two tripods: group A = legs 1,3,5 and group B = legs 2,4,6
2. Phase 1: Group A lifts and swings forward (swing phase) while Group B stays on the ground and pushes backward (stance phase) — this moves the body forward
3. Phase 2: Roles reverse — Group B swings while Group A pushes
4. Each leg function must handle both the lift/forward-swing and the push-backward motion
5. Need a delay between phases so servos complete their motion

The key insight: during stance phase, the leg pushes backward against the ground, which propels the body forward. During swing phase, the leg lifts, moves forward through the air, and places down — repositioning for the next stance.

Here's the tripod gait walk function for the hexapod:

```cpp
#include <Servo.h>

// Each leg has 3 servos: coxa (horizontal), femur (vertical lift), tibia (vertical extend)
// moveLegN() = forward swing + stance for leg N

void walkForward(int steps) {
  for (int i = 0; i < steps; i++) {
    // Phase 1: Tripod A (legs 1, 3, 5) swings forward
    //          Tripod B (legs 2, 4, 6) pushes backward (stance)
    moveLeg1();
    moveLeg3();
    moveLeg5();
    delay(500);  // Allow swing phase to complete

    // Phase 2: Tripod B (legs 2, 4, 6) swings forward
    //          Tripod A (legs 1, 3, 5) pushes backward (stance)
    moveLeg2();
    moveLeg4();
    moveLeg6();
    delay(500);  // Allow swing phase to complete
  }
}

// Example leg movement function (leg 1)
// Swing phase: lift femur, move coxa forward, lower tibia
// Stance phase: push coxa backward while leg is on the ground
void moveLeg1() {
  // Swing phase — lift and move forward
  s2.write(120);   // Femur up (lift leg off ground)
  delay(100);
  s1.write(60);    // Coxa forward (swing leg forward through air)
  delay(100);
  s3.write(100);   // Tibia extend (prepare to place down)
  delay(100);
  s2.write(90);    // Femur down (place leg on ground)
  delay(100);

  // Stance phase — push backward on the ground
  s1.write(120);   // Coxa backward (pushes body forward)
  delay(100);
}

void moveLeg2() {
  s8.write(120);
  delay(100);
  s7.write(60);
  delay(100);
  s9.write(100);
  delay(100);
  s8.write(90);
  delay(100);
  s7.write(120);
  delay(100);
}

void moveLeg3() {
  s11.write(120);
  delay(100);
  s10.write(60);
  delay(100);
  s12.write(100);
  delay(100);
  s11.write(90);
  delay(100);
  s10.write(120);
  delay(100);
}

void moveLeg4() {
  s17.write(120);
  delay(100);
  s16.write(60);
  delay(100);
  s18.write(100);
  delay(100);
  s17.write(90);
  delay(100);
  s16.write(120);
  delay(100);
}

void moveLeg5() {
  s20.write(120);
  delay(100);
  s19.write(60);
  delay(100);
  s21.write(100);
  delay(100);
  s20.write(90);
  delay(100);
  s19.write(120);
  delay(100);
}

void moveLeg6() {
  s23.write(120);
  delay(100);
  s22.write(60);
  delay(100);
  s24.write(100);
  delay(100);
  s23.write(90);
  delay(100);
  s22.write(120);
  delay(100);
}
```

Key points:
1. **Tripod stability**: At any time, three legs form a stable triangle supporting the body. This is why the tripod gait is the most common hexapod walking pattern.
2. **Swing vs. stance**: During swing, the leg lifts off the ground and moves forward. During stance, the leg stays planted and pushes backward, propelling the body forward.
3. **Phase alternation**: Tripod A (legs 1,3,5) and Tripod B (legs 2,4,6) alternate. While one group swings, the other provides stance support.
4. **Delays**: The `delay(500)` between phases gives the servos time to complete their motion before the next group starts. The `delay(100)` between individual servo writes lets each joint reach its target.
5. **Angle values**: The specific angles (60, 90, 120, etc.) are starting points — calibrate them for your robot's physical geometry. The coxa servo moves the leg horizontally, the femur lifts it vertically, and the tibia controls leg extension.

The HC-SR04 ultrasonic sensor is mounted in the hexapod's head (the "eyes") and detects objects in front of the robot. When an object comes within approximately 30–40 cm, the robot enters attack mode — preparing to bite with its mandibles.

## How the HC-SR04 Works

The HC-SR04 has two ultrasonic transducers: a trigger (TX) and an echo (RX). The trigger pin (`trigPin`, defined as pin 7) sends a 10µs HIGH pulse, which causes the sensor to emit 8 cycles of ultrasonic burst at 40 kHz. The echo pin (`echoPin`, defined as pin 6) goes HIGH when the burst is sent and stays HIGH until the reflected signal returns.

## Distance Calculation

The distance is calculated from the echo pulse duration:

```cpp
#define trigPin 7
#define echoPin 6

long readUltrasonic() {
  digitalWrite(trigPin, LOW);
  delayMicroseconds(2);
  digitalWrite(trigPin, HIGH);
  delayMicroseconds(10);
  digitalWrite(trigPin, LOW);

  long duration = pulseIn(echoPin, HIGH);
  // Speed of sound = 343 m/s = 0.0343 cm/µs
  // Distance = (duration / 2) × 0.0343  (divide by 2 for round trip)
  long distance = (duration / 2) / 29.1;  // cm
  return distance;
}
```

## Attack Mode Trigger

In the main loop, the distance is checked. If an object is detected within ~30–40 cm, the robot calls `prepareAttack()`:

```cpp
void loop() {
  long dist = readUltrasonic();

  if (dist > 0 && dist <= 40) {
    // Object detected within 40 cm — enter attack mode
    prepareAttack();
  } else {
    // No nearby object — dismiss attack posture
    dismissAttack();
  }

  // Also handle Bluetooth commands
  if (Bluetooth.available() > 0) {
    int cmd = Bluetooth.read();
    // ... command handling
  }
}

void prepareAttack() {
  // Raise head, open mandibles, prepare to bite
  s14.write(30);   // Head tilt down toward target
  s15.write(72);   // Head roll center
  s13.write(40);   // Mandibles open wide
  delay(200);
  // Bite!
  s13.write(120);  // Mandibles close (bite)
  delay(300);
}

void dismissAttack() {
  // Return to neutral posture
  s14.write(55);   // Head tilt neutral
  s13.write(90);   // Mandibles center
}
```

Key points:
1. **Threshold ~30–40 cm**: The robot reacts when an object is close enough to be a threat or target. The exact threshold can be tuned by changing the comparison value.
2. **`pulseIn()`**: Measures the echo pulse duration in microseconds. The formula `(duration / 2) / 29.1` converts this to centimeters (29.1 µs/cm for the one-way trip at the speed of sound).
3. **Attack sequence**: `prepareAttack()` tilts the head toward the object, opens the mandibles (SG90 servo `s13`), then closes them to simulate a bite. `dismissAttack()` returns to neutral posture when no object is nearby.
4. **Pin assignments**: `trigPin` = 7, `echoPin` = 6 — these are defined at the top of the sketch and correspond to the HC-SR04's trigger and echo pins.

The custom PCB shield (designed in EasyEDA) includes a battery voltage monitor that lets the Arduino sense when the 3S LiPo battery (~12V nominal) is running low. A resistor divider scales the battery voltage down to a safe range for the Arduino's analog input, and an LED on pin 10 provides a visual low-battery warning.

## Resistor Divider Circuit

The Arduino Mega's analog pins can read 0–5V. The 3S LiPo ranges from ~12.6V (fully charged) down to ~9.9V (empty). A voltage divider scales this to under 5V:

```
Battery (+12V) ──[R1]──┬──[R2]── GND
                        │
                    Analog Pin

Vout = Vin × R2 / (R1 + R2)
```

For example, with R1 = 30kΩ and R2 = 10kΩ:
- At 12.6V: Vout = 12.6 × 10 / (30 + 10) = 3.15V
- At 11.0V: Vout = 11.0 × 10 / (30 + 10) = 2.75V
- At 9.9V:  Vout = 9.9 × 10 / (30 + 10) = 2.48V

All safely within the 0–5V analog range.

## Arduino Code

```cpp
#define ledB 10
#define batteryPin A0  // Analog pin connected to voltage divider

void setup() {
  pinMode(ledB, OUTPUT);
}

void loop() {
  int raw = analogRead(batteryPin);
  // Convert ADC value (0-1023) to voltage at the analog pin
  float pinVoltage = raw * (5.0 / 1023.0);
  // Scale back up to battery voltage using divider ratio
  // Ratio = (R1 + R2) / R2 = (30k + 10k) / 10k = 4.0
  float batteryVoltage = pinVoltage * 4.0;

  if (batteryVoltage < 11.0) {
    digitalWrite(ledB, HIGH);  // Turn on low-battery LED
  } else {
    digitalWrite(ledB, LOW);   // Battery OK
  }
}
```

Key points:
1. **Resistor divider**: Scales the ~12V battery down to ~3V at the analog pin. The exact resistor values depend on your PCB design, but the principle is the same — divide by a known ratio and multiply back in software.
2. **LED on pin 10**: `ledB` is defined as pin 10 in the sketch. When the calculated battery voltage drops below ~11V, the LED turns on as a visual warning to recharge.
3. **ADC conversion**: `analogRead()` returns 0–1023 (10-bit ADC on the Mega). Multiply by `5.0 / 1023.0` to get the pin voltage, then by the divider ratio to recover the actual battery voltage.
4. **3S LiPo range**: A 3S LiPo is ~12.6V fully charged and should not drop below ~9.9V (3.3V/cell). The 11V threshold gives a safety margin before the battery is critically depleted.
5. **Custom PCB**: The shield includes this divider circuit along with power filtering capacitors, servo connectors, an optional NRF24L01 slot, and multiple 5V/GND pins for clean wiring.

There are two likely causes: the `delay()` calls in your leg movement functions block the loop from reading Bluetooth, and `SoftwareSerial` at 38400 baud is near its reliability limit on an AVR Arduino.

## Cause 1: Blocking delays prevent Bluetooth reads

The main loop checks `Bluetooth.available()` only when it reaches the top of `loop()`. If a leg movement function like `moveLeg1()` contains multiple `delay()` calls totaling hundreds of milliseconds, the Arduino cannot read incoming Bluetooth data during that time. Any bytes that arrive while the code is stuck in a `delay()` are buffered in the SoftwareSerial receive buffer, but if the buffer fills up (64 bytes on AVR), additional bytes are lost.

```cpp
void loop() {
  if (Bluetooth.available() > 0) {
    int cmd = Bluetooth.read();
    switch (cmd) {
      case 2:
        moveForward();  // This calls moveLeg1()...moveLeg6() with delays
        break;
      // ...
    }
  }
}
```

If `moveForward()` takes 3+ seconds to complete (6 legs × multiple delays), any commands sent during that window are either buffered or dropped.

## Cause 2: SoftwareSerial at 38400 baud

`SoftwareSerial` relies on pin-change interrupts and software timing. At 38400 baud, each bit is only ~26µs wide. On an AVR Arduino running at 16MHz, `SoftwareSerial` can struggle to reliably decode at this speed, especially if other interrupts (like servo timers) fire during reception. The Servo library uses Timer1, which can interfere with SoftwareSerial's timing-sensitive receive path.

## Solutions

### Fix 1: Use HardwareSerial instead of SoftwareSerial

The Arduino Mega has 4 hardware serial ports (Serial1, Serial2, Serial3). Use one of these instead of SoftwareSerial — hardware UART is far more reliable at 38400 baud and is not affected by servo timer interrupts:

```cpp
// Replace SoftwareSerial with HardwareSerial on the Mega
#define Bluetooth Serial1  // Hardware serial on pins 18 (RX) and 19 (TX)

void setup() {
  Serial.begin(38400);   // USB serial for debugging
  Bluetooth.begin(38400);  // HC-05 on hardware serial
}

void loop() {
  if (Bluetooth.available() > 0) {
    int cmd = Bluetooth.read();
    // ...
  }
}
```

This is the single most effective fix. The Mega's hardware UART handles 38400 baud effortlessly, even with servo timers running.

### Fix 2: Non-blocking leg movement with millis()

Replace `delay()` calls with `millis()`-based timing so the loop can continue reading Bluetooth while legs move:

```cpp
unsigned long legTimer = 0;
int legStep = 0;

void moveLeg1NonBlocking() {
  if (millis() - legTimer >= 100) {
    legTimer = millis();
    switch (legStep) {
      case 0: s2.write(120); legStep++; break;
      case 1: s1.write(60);  legStep++; break;
      case 2: s3.write(100); legStep++; break;
      case 3: s2.write(90);  legStep++; break;
      case 4: s1.write(120); legStep = 0; break;
    }
  }
}
```

This lets `loop()` check `Bluetooth.available()` on every iteration, even while a leg is mid-motion.

### Fix 3: Increase the SoftwareSerial buffer (if staying with SoftwareSerial)

If you must use SoftwareSerial, increase its buffer size:

```cpp
// Before including SoftwareSerial.h, define a larger buffer
#define _SS_MAX_RX_BUFF 256
#include <SoftwareSerial.h>
```

This gives more room for incoming bytes during long leg movements, reducing the chance of buffer overflow.

## Summary

The most impactful fix is switching to **HardwareSerial** (Serial1/Serial2/Serial3 on the Mega). The Mega has 4 hardware UARTs specifically for this reason — use them instead of SoftwareSerial when servo timers are active. Combined with non-blocking leg movement, this eliminates dropped commands.

Here are the head, mandibles, and tail control functions for the hexapod. The head has two MG996R servos for roll (s15) and tilt (s14), an SG90 for the mandibles (s13), and an MG996R for the tail (s5):

```cpp
#include <Servo.h>

// Head servos
Servo s15;  // Head roll (MG996R)
Servo s14;  // Head tilt (MG996R)
Servo s13;  // Mandibles (SG90)
Servo s5;   // Tail (MG996R)

// Calibration positions (from setup)
const int HEAD_ROLL_CENTER  = 72;
const int HEAD_TILT_CENTER  = 55;
const int MANDIBLES_CENTER  = 90;
const int TAIL_CENTER      = 90;

void setup() {
  s15.attach(36, 600, 2400);
  s14.attach(35, 600, 2400);
  s13.attach(34, 600, 2400);
  s5.attach(26, 600, 2400);

  // Initialize to calibration positions
  s15.write(HEAD_ROLL_CENTER);
  s14.write(HEAD_TILT_CENTER);
  s13.write(MANDIBLES_CENTER);
  s5.write(TAIL_CENTER);
}

// ── Head control ──

void headLeft() {
  s15.write(HEAD_ROLL_CENTER - 30);  // Roll head left
  delay(300);
}

void headRight() {
  s15.write(HEAD_ROLL_CENTER + 30);  // Roll head right
  delay(300);
}

void headCenter() {
  s15.write(HEAD_ROLL_CENTER);  // Return to center
  delay(300);
}

void headUp() {
  s14.write(HEAD_TILT_CENTER - 20);  // Tilt head up
  delay(300);
}

void headDown() {
  s14.write(HEAD_TILT_CENTER + 20);  // Tilt head down
  delay(300);
}

void headTiltCenter() {
  s14.write(HEAD_TILT_CENTER);  // Return tilt to center
  delay(300);
}

// ── Mandibles (bite) ──

void openMandibles() {
  s13.write(40);   // Open wide
  delay(300);
}

void closeMandibles() {
  s13.write(120);  // Close (bite)
  delay(300);
}

void mandiblesCenter() {
  s13.write(MANDIBLES_CENTER);  // Neutral position
  delay(300);
}

void bite() {
  openMandibles();
  delay(200);
  closeMandibles();
  delay(300);
  mandiblesCenter();
}

// ── Tail control ──

void tailWag() {
  for (int i = 0; i < 3; i++) {
    s5.write(TAIL_CENTER + 25);
    delay(200);
    s5.write(TAIL_CENTER - 25);
    delay(200);
  }
  s5.write(TAIL_CENTER);
}

void tailUp() {
  s5.write(TAIL_CENTER - 40);  // Raise tail
  delay(300);
}

void tailDown() {
  s5.write(TAIL_CENTER + 40);  // Lower tail
  delay(300);
}

void tailCenter() {
  s5.write(TAIL_CENTER);
  delay(300);
}

// ── Attack sequence ──

void prepareAttack() {
  headDown();       // Tilt head toward target
  openMandibles();  // Open mandibles wide
  delay(500);
  closeMandibles(); // Bite!
  delay(300);
}

void dismissAttack() {
  headTiltCenter();  // Head back to neutral
  mandiblesCenter(); // Mandibles to neutral
}

void loop() {
  // Main control loop
}
```

Key points:
1. **Calibration constants**: `HEAD_ROLL_CENTER = 72`, `HEAD_TILT_CENTER = 55`, `MANDIBLES_CENTER = 90` match the initial positions set in `setup()`. Using constants makes it easy to recalibrate — change the value in one place.
2. **Head roll (s15)**: Rotates the head left/right. The MG996R provides enough torque for the head assembly including the HC-SR04 sensor.
3. **Head tilt (s14)**: Tilts the head up/down. Used in `prepareAttack()` to aim the head at the detected object.
4. **Mandibles (s13)**: The SG90 is a smaller, lighter servo suitable for the mandibles. `bite()` opens then closes them in sequence.
5. **Tail (s5)**: The MG996R drives the tail/abdomen. `tailWag()` sweeps it side to side three times for a lifelike animation.
6. **Attack sequence**: `prepareAttack()` combines head tilt down + mandible open + mandible close. `dismissAttack()` returns everything to neutral. These are triggered when the ultrasonic sensor detects an object within ~30–40 cm.

Here's the complete `setup()` function with all pin definitions, sensor initialization, Bluetooth setup, and servo calibration:

```cpp
#include <Servo.h>
#include <SoftwareSerial.h>

#define trigPin 7
#define echoPin 6
#define ledB 10

SoftwareSerial Bluetooth(12, 9);  // HC-05: RX=12, TX=9

// Leg servos
Servo s24; Servo s23; Servo s22;
Servo s21; Servo s20; Servo s19;
