  radio.setDataRate(RF24_250KBPS);
  radio.setPALevel(RF24_PA_LOW);
  radio.startListening();

  // Reset data struct
  memset(&data, 0, sizeof(data));
}

void loop() {
  // Check for incoming radio packet
  if (radio.available()) {
    radio.read(&data, sizeof(data));

    // Map joystick Y-axis (0-255) to throttle (-255 to +255)
    // Center position ~127 = stopped, 0 = full reverse, 255 = full forward
    int throttle = map(data.j1PotY, 0, 255, -255, 255);

    // Map joystick X-axis (0-255) to steering (-255 to +255)
    // Center ~127 = straight, 0 = full left, 255 = full right
    int steering = map(data.j1PotX, 0, 255, -255, 255);

    // Calculate motor speeds with differential steering
    int motorA_Speed = throttle + steering;  // Left motor
    int motorB_Speed = throttle - steering;  // Right motor

    // Constrain speeds to valid PWM range (0-255)
    motorA_Speed = constrain(motorA_Speed, -255, 255);
    motorB_Speed = constrain(motorB_Speed, -255, 255);

    // ── Motor A (left) ──
    if (motorA_Speed >= 0) {
      // Forward
      digitalWrite(in1, HIGH);
      digitalWrite(in2, LOW);
      analogWrite(enA, motorA_Speed);
    } else {
